eventScripts.script:
if initialChange:
	return
temp = currentValue.value
tag_ventilatie = "[default]Pornire_stare_ventilatie"
tag_incalzire = "[default]Pornire_stare_incalzire" 

if temp > 25:
	system.tag.writeBlocking([tag_ventilatie], [1])
elif temp < 22:
	system.tag.writeBlocking([tag_ventilatie], [0])

if temp < 7:
	system.tag.writeBlocking([tag_incalzire], [1])
elif temp > 10:
	system.tag.writeBlocking([tag_incalzire], [0])
